import { createGlobalValueSetter } from 'Shared/store/createGlobalValueSetter';
import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';
import { SidebarNameE } from 'Components/sidebar/types/SidebarNameE';
import { SidebarPropsT } from 'Components/sidebar/types/SidebarPropsT';

const updateSidebar = createGlobalValueSetter(GlobalStoreFieldE.SIDEBAR);

export const sidebarService = {
  openFirst: <N extends SidebarNameE>(
    sidebarName: N,
    ...args: SidebarPropsT[N] extends void ? [] : [props: SidebarPropsT[N]]
  ) => {
    updateSidebar(() => [
      {
        deleted: false,
        name: sidebarName,
        props: args[0],
      },
    ]);
  },
  open: <N extends SidebarNameE>(
    sidebarName: N,
    ...args: SidebarPropsT[N] extends void ? [] : [props: SidebarPropsT[N]]
  ) => {
    updateSidebar(currentSidebar => {
      const currentSidebarWithoutNew = currentSidebar.filter(
        item => item.name !== sidebarName,
      );

      return [
        {
          deleted: false,
          name: sidebarName,
          props: args[0],
        },
        ...currentSidebarWithoutNew,
      ];
    });
  },
  close: (sidebarName: SidebarNameE) => {
    updateSidebar(sidebars =>
      sidebars.map(sidebar =>
        sidebar.name === sidebarName ? { ...sidebar, deleted: true } : sidebar,
      ),
    );
  },
  closeAll: () => {
    updateSidebar(sidebars => sidebars.map(s => ({ ...s, deleted: true })));
  },
  finalizeClose: (sidebarName: SidebarNameE) => {
    updateSidebar(sidebars =>
      sidebars.filter(sidebar => sidebar.name !== sidebarName),
    );
  },
};

